 78→/// Disk-backed cache for storing and loading [`BehaviorMap`]s.
 79→#[derive(Debug)]
 80→pub struct BehaviorMapCache {
 81→    cache_dir: PathBuf,
 82→}
 83→
 84→impl BehaviorMapCache {
 85→    /// Create a new cache backed by the given directory.
 86→    ///
 87→    /// Creates the directory (and parents) if it doesn't exist.
 88→    pub fn new(cache_dir: PathBuf) -> Result<Self, CacheError> {
 89→        fs::create_dir_all(&cache_dir)?;
 90→        Ok(Self { cache_dir })
 91→    }
 92→
 93→    /// Load a behavior map for the given function ID, if one exists.
 94→    ///
 95→    /// Returns `Ok(None)` on cache miss, protocol version mismatch,
 96→    /// or deserialization failure (gracefully handles old cache format).
 97→    pub fn load(&self, function_id: &str) -> Result<Option<BehaviorMap>, CacheError> {
 98→        let path = self.path_for(function_id);
 99→        match fs::read_to_string(&path) {
100→            Ok(contents) => {
101→                let entry: BehaviorMapCacheEntry = match serde_json::from_str(&contents) {
102→                    Ok(e) => e,
103→                    // Old bare-JSON format or corrupt entry → cache miss
104→                    Err(_) => return Ok(None),
105→                };
106→                if entry.protocol_version != PROTOCOL_VERSION {
107→                    return Ok(None);
108→                }
109→                Ok(Some(entry.behavior_map))
110→            }
111→            Err(e) if e.kind() == std::io::ErrorKind::NotFound => Ok(None),
112→            Err(e) => Err(CacheError::Io(e)),
113→        }
114→    }
115→
116→    /// Store a behavior map to disk using atomic write (temp file + rename).
117→    pub fn store(&self, map: &BehaviorMap) -> Result<(), CacheError> {
118→        let path = self.path_for(&map.function_id);
119→        let entry = BehaviorMapCacheEntry {
120→            protocol_version: PROTOCOL_VERSION.to_string(),
121→            behavior_map: map.clone(),
122→        };
123→        let json = serde_json::to_string_pretty(&entry)?;
124→
125→        if let Some(parent) = path.parent() {
126→            fs::create_dir_all(parent)?;
127→        }
128→
129→        let tmp_path = path.with_extension("json.tmp");
130→        fs::write(&tmp_path, json)?;
131→        fs::rename(&tmp_path, &path)?;
132→
133→        Ok(())
134→    }
135→
136→    /// Check whether a cached behavior map exists and its fingerprint matches.
137→    ///
138→    /// Returns `true` if the cache contains a version-compatible map for
139→    /// `function_id` whose fingerprint equals `current_fingerprint`.
140→    pub fn is_fresh(
141→        &self,
142→        function_id: &str,
143→        current_fingerprint: &str,
144→    ) -> Result<bool, CacheError> {
145→        match self.load(function_id)? {
146→            Some(map) => Ok(map
147→                .fingerprint
148→                .as_deref()
149→                .is_some_and(|fp| fp == current_fingerprint)),
150→            None => Ok(false),
151→        }
152→    }
153→
154→    /// Default cache directory relative to a project root: `<project_root>/.shatter/cache/`.
155→    pub fn default_dir(project_root: &Path) -> PathBuf {
156→        project_root.join(".shatter").join("cache")
157→    }
158→
159→    fn path_for(&self, function_id: &str) -> PathBuf {
160→        let mut p = cache_base_path(&self.cache_dir, function_id);
161→        p.set_extension("json");
162→        p
163→    }
164→}
165→
166→/// Disk-backed cache for storing and loading [`FunctionSpec`]s.
167→///
168→/// Colocated with behavior map cache entries using `.spec.json` extension.
169→#[derive(Debug)]
170→pub struct SpecCache {
171→    cache_dir: PathBuf,
172→}
173→
174→impl SpecCache {
175→    /// Create a new spec cache backed by the given directory.
176→    ///
177→    /// Creates the directory (and parents) if it doesn't exist.
178→    pub fn new(cache_dir: PathBuf) -> Result<Self, CacheError> {
179→        fs::create_dir_all(&cache_dir)?;
180→        Ok(Self { cache_dir })
181→    }
182→
183→    /// Load a function spec for the given function ID, if one exists.
184→    ///
185→    /// Returns `Ok(None)` on cache miss, protocol version mismatch,
186→    /// or deserialization failure.
187→    pub fn load(&self, function_id: &str) -> Result<Option<FunctionSpec>, CacheError> {
188→        let path = self.path_for(function_id);
189→        match fs::read_to_string(&path) {
190→            Ok(contents) => {
191→                let entry: SpecCacheEntry = match serde_json::from_str(&contents) {
192→                    Ok(e) => e,
193→                    Err(_) => return Ok(None),
194→                };
195→                if entry.protocol_version != PROTOCOL_VERSION {
196→                    return Ok(None);
197→                }
198→                Ok(Some(entry.spec))
199→            }
200→            Err(e) if e.kind() == std::io::ErrorKind::NotFound => Ok(None),
201→            Err(e) => Err(CacheError::Io(e)),
202→        }
203→    }
204→
205→    /// Store a function spec to disk using atomic write (temp file + rename).
206→    pub fn store(&self, function_id: &str, spec: &FunctionSpec) -> Result<(), CacheError> {
207→        let path = self.path_for(function_id);
208→        let entry = SpecCacheEntry {
209→            protocol_version: PROTOCOL_VERSION.to_string(),
210→            spec: spec.clone(),
211→        };
212→        let json = serde_json::to_string_pretty(&entry)?;
213→
214→        if let Some(parent) = path.parent() {
215→            fs::create_dir_all(parent)?;
216→        }
217→
218→        let tmp_path = path.with_extension("spec.json.tmp");
219→        fs::write(&tmp_path, json)?;
220→        fs::rename(&tmp_path, &path)?;
221→
222→        Ok(())
223→    }
224→
225→    /// Check whether a cached spec exists and its fingerprint matches.
226→    pub fn is_fresh(
227→        &self,
228→        function_id: &str,
229→        current_fingerprint: &str,
230→    ) -> Result<bool, CacheError> {
231→        match self.load(function_id)? {
232→            Some(spec) => Ok(spec
233→                .fingerprint
234→                .as_deref()
235→                .is_some_and(|fp| fp == current_fingerprint)),
236→            None => Ok(false),
237→        }
238→    }
239→
240→    /// Default spec cache directory (same as behavior map cache).
241→    pub fn default_dir(project_root: &Path) -> PathBuf {
242→        project_root.join(".shatter").join("cache")
243→    }
244→
245→    fn path_for(&self, function_id: &str) -> PathBuf {
246→        let mut p = cache_base_path(&self.cache_dir, function_id);
247→        p.set_extension("spec.json");
248→        p
249→    }
250→}
251→
252→/// Sanitize a single path component for safe use as a filename.
253→///
254→/// Replaces unsafe characters with underscores to prevent path traversal attacks.
255→/// Called per-component after splitting on `/` and `:`, so those delimiters
256→/// are not expected in the input.
257→fn sanitize_component(component: &str) -> String {
258→    component
259→        .chars()
260→        .enumerate()
261→        .map(|(i, c)| match c {
262→            '\\' | '*' | '?' | '"' | '<' | '>' | '|' | '\0' => '_',
263→            '.' if i == 0 => '_', // prevent hidden files for leading dots
264→            _ => c,
265→        })
266→        .collect()
267→}
