  1→//! Per-function fingerprinting for staleness detection.
  2→//!
  3→//! A fingerprint is a stable SHA-256 hash of a function's source text,
  4→//! parameter types, and branch structure. When a fingerprint matches a
  5→//! previously cached value, the function is unchanged and can be skipped
  6→//! during re-exploration.
  7→
  8→use std::collections::{HashMap, HashSet};
  9→use std::fmt::Write as _;
 10→use std::path::Path;
 11→
 12→use sha2::{Digest, Sha256};
 13→
 14→use crate::protocol::FunctionAnalysis;
 15→
 16→/// Compute a hex-encoded SHA-256 fingerprint for a function.
 17→///
 18→/// The fingerprint incorporates:
 19→/// - The function's source text (verbatim, including whitespace)
 20→/// - Parameter names and types (sorted by name for stability)
 21→/// - Branch structure: IDs, lines, condition text, types (sorted by ID)
 22→///
 23→/// Any change to these inputs produces a different fingerprint.
 24→pub fn compute_function_fingerprint(source_text: &str, analysis: &FunctionAnalysis) -> String {
 25→    let mut hasher = Sha256::new();
 26→
 27→    // Hash source text.
 28→    hasher.update(b"source:");
 29→    hasher.update(source_text.as_bytes());
 30→
 31→    // Hash parameters (sorted by name for determinism).
 32→    let mut params: Vec<_> = analysis
 33→        .params
 34→        .iter()
 35→        .map(|p| {
 36→            let mut s = String::new();
 37→            let _ = write!(s, "{}:{:?}", p.name, p.typ);
 38→            if let Some(ref tn) = p.type_name {
 39→                let _ = write!(s, "/{tn}");
 40→            }
 41→            s
 42→        })
 43→        .collect();
 44→    params.sort();
 45→
 46→    hasher.update(b"params:");
 47→    for p in &params {
 48→        hasher.update(p.as_bytes());
 49→        hasher.update(b"\n");
 50→    }
 51→
 52→    // Hash branch structure (sorted by branch ID for determinism).
 53→    let mut branches: Vec<_> = analysis
 54→        .branches
 55→        .iter()
 56→        .map(|b| {
 57→            let mut s = String::new();
 58→            let _ = write!(s, "{}:{}:{:?}:{}", b.id, b.line, b.branch_type, b.condition_text);
 59→            s
 60→        })
 61→        .collect();
 62→    branches.sort();
 63→
 64→    hasher.update(b"branches:");
 65→    for b in &branches {
 66→        hasher.update(b.as_bytes());
 67→        hasher.update(b"\n");
 68→    }
 69→
 70→    format!("{:x}", hasher.finalize())
 71→}
 72→
 73→/// Compute a deep fingerprint that incorporates callee fingerprints.
 74→///
 75→/// Extends the shallow fingerprint by hashing in the deep fingerprints of all
 76→/// in-scope callees (sorted by name for determinism). Callees not present in
 77→/// `callee_deep_fingerprints` are ignored (they are out-of-scope and assumed stable).
 78→///
 79→/// Because scans process functions leaves-first, callee deep fingerprints are
 80→/// always available before the caller is processed.
 81→pub fn compute_deep_fingerprint(
 82→    shallow_fingerprint: &str,
 83→    callee_deep_fingerprints: &HashMap<String, String>,
 84→    callees: &HashSet<String>,
 85→) -> String {
 86→    let mut hasher = Sha256::new();
 87→    hasher.update(b"shallow:");
 88→    hasher.update(shallow_fingerprint.as_bytes());
 89→
 90→    let mut callee_fps: Vec<(&str, &str)> = callees
 91→        .iter()
 92→        .filter_map(|c| {
 93→            callee_deep_fingerprints
 94→                .get(c)
 95→                .map(|fp| (c.as_str(), fp.as_str()))
 96→        })
 97→        .collect();
 98→    callee_fps.sort_by_key(|(name, _)| *name);
 99→
100→    hasher.update(b"callees:");
101→    for (name, fp) in &callee_fps {
102→        hasher.update(name.as_bytes());
103→        hasher.update(b"=");
104→        hasher.update(fp.as_bytes());
105→        hasher.update(b"\n");
106→    }
107→
108→    format!("{:x}", hasher.finalize())
109→}
110→
111→/// Compute deep fingerprints for all functions in a single file.
112→///
113→/// For each analysis, computes a shallow fingerprint from source text + metadata,
114→/// then composes it with callee deep fingerprints. Functions are processed in
115→/// dependency order (leaves first via Kahn's algorithm on out-edges) so callee
116→/// fingerprints are available when computing callers. Out-of-scope callees
117→/// (not in `analyses`) are ignored. Cycles are broken by processing remaining
118→/// functions with partial callee fingerprints.
119→///
120→/// Returns a map from function name to deep fingerprint.
121→pub fn compute_deep_fingerprints(
122→    file_path: &Path,
123→    analyses: &[FunctionAnalysis],
124→) -> Result<HashMap<String, String>, std::io::Error> {
125→    let name_set: HashSet<&str> = analyses.iter().map(|a| a.name.as_str()).collect();
126→
127→    // Compute shallow fingerprints for all functions.
128→    let mut shallow: HashMap<String, String> = HashMap::new();
129→    for func in analyses {
130→        let source = extract_function_source(file_path, func.start_line, func.end_line)?;
131→        shallow.insert(func.name.clone(), compute_function_fingerprint(&source, func));
132→    }
133→
134→    // Build in-scope callee sets per function.
135→    let callees_map: HashMap<&str, HashSet<String>> = analyses
136→        .iter()
137→        .map(|func| {
138→            let callees: HashSet<String> = func
139→                .dependencies
140→                .iter()
141→                .map(|d| d.symbol.clone())
142→                .filter(|s| name_set.contains(s.as_str()))
143→                .collect();
144→            (func.name.as_str(), callees)
145→        })
146→        .collect();
147→
148→    // Kahn's algorithm: process leaves (no in-scope callees) first.
149→    // out_degree = number of unprocessed in-scope callees.
150→    let mut out_degree: HashMap<&str, usize> = analyses
151→        .iter()
152→        .map(|f| {
153→            (
154→                f.name.as_str(),
155→                callees_map.get(f.name.as_str()).map_or(0, HashSet::len),
156→            )
157→        })
158→        .collect();
159→
160→    // Reverse: callee → list of callers.
161→    let mut reverse: HashMap<&str, Vec<&str>> = HashMap::new();
162→    for (&caller, callees) in &callees_map {
163→        for callee in callees {
164→            reverse.entry(callee.as_str()).or_default().push(caller);
165→        }
166→    }
167→
168→    let mut queue: Vec<&str> = out_degree
169→        .iter()
170→        .filter(|(_, deg)| **deg == 0)
171→        .map(|(&name, _)| name)
172→        .collect();
173→    queue.sort();
174→
175→    let mut deep: HashMap<String, String> = HashMap::new();
176→
177→    while let Some(func_name) = queue.pop() {
178→        if let Some(sfp) = shallow.get(func_name) {
179→            let callees = callees_map
180→                .get(func_name)
181→                .cloned()
182→                .unwrap_or_default();
183→            deep.insert(
184→                func_name.to_string(),
185→                compute_deep_fingerprint(sfp, &deep, &callees),
186→            );
187→        }
188→
189→        if let Some(callers) = reverse.get(func_name) {
190→            for &caller in callers {
191→                if let Some(deg) = out_degree.get_mut(caller) {
192→                    *deg = deg.saturating_sub(1);
193→                    if *deg == 0 {
194→                        queue.push(caller);
195→                        queue.sort();
196→                    }
197→                }
198→            }
199→        }
200→    }
201→
202→    // Cycle remnants: process with partial callee fingerprints.
203→    for func in analyses {
204→        if !deep.contains_key(&func.name)
205→            && let Some(sfp) = shallow.get(&func.name)
206→        {
207→            let callees = callees_map
208→                .get(func.name.as_str())
209→                .cloned()
210→                .unwrap_or_default();
211→            deep.insert(
212→                func.name.clone(),
213→                compute_deep_fingerprint(sfp, &deep, &callees),
214→            );
215→        }
216→    }
217→
218→    Ok(deep)
219→}
220→
221→/// Extract the source text of a function from a file given line boundaries.
222→///
223→/// Reads lines `start_line..=end_line` (1-indexed) from the file and joins
224→/// them with newlines. Returns an error if the file cannot be read.
225→pub fn extract_function_source(
226→    file_path: &Path,
227→    start_line: u32,
228→    end_line: u32,
229→) -> Result<String, std::io::Error> {
230→    let contents = std::fs::read_to_string(file_path)?;
231→    let lines: Vec<&str> = contents.lines().collect();
232→    let start = (start_line as usize).saturating_sub(1);
233→    let end = (end_line as usize).min(lines.len());
234→    Ok(lines[start..end].join("\n"))
235→}
