        let analyses = vec![make_analysis("leaf", 1, 1, vec![])];
        let fps = compute_deep_fingerprints(&file, &analyses, &HashMap::new()).unwrap();

        assert_eq!(fps.len(), 1);
        assert!(fps.contains_key("leaf"));
