        let fps2 = compute_deep_fingerprints(&file2, &analyses, &HashMap::new()).unwrap();

        // leaf changed → leaf's FP differs
        assert_ne!(fps1["leaf"], fps2["leaf"]);
        // caller's source is the same but callee changed → caller's deep FP differs
