        // "external" is not in analyses — should be ignored
        let analyses = vec![make_analysis("caller", 1, 1, vec!["external"])];
        let fps = compute_deep_fingerprints(&file, &analyses, &HashMap::new()).unwrap();

        assert_eq!(fps.len(), 1);
