    fn make_exploration_result(
        name: &str,
        iterations: u32,
        unique_paths: usize,
    ) -> ObservationOutput {
        ObservationOutput {
            function_name: name.to_string(),
            iterations,
            unique_paths,
            lines_covered: 8,
            total_lines: 10,
            new_path_executions: vec![],
