            make_eq_class(
                vec![(0, false), (1, true)],
                vec![json!(-3)],
                Some(json!("negative")),
                None,
                vec![Precondition::AllNegative { param_index: 0 }],
                8,
            ),
            // Class with only branch 1 (Random) → Observed
            make_eq_class(
                vec![(1, false)],
                vec![json!(0)],
                Some(json!("zero")),
