        };

        let plan = compute_incremental_plan(&file, &[analysis], &existing).unwrap();
        assert!(plan.stale.is_empty(), "expected no stale, got: {:?}", plan.stale);
        assert_eq!(plan.fresh, vec!["add"]);
        assert!(plan.removed.is_empty());
    }

