        assert_eq!(
            categorize_invariant_kind(&InvariantKind::NumericComparison {
                path: vec![],
                op: ComparisonOp::Gt,
                value: 0.0,
            }),
            InvariantCategory::NumericBound
        );
        assert_eq!(
            categorize_invariant_kind(&InvariantKind::NumericConstant {
