2901→/// Run the stale command: check which functions are stale relative to a spec file.
2902→///
2903→/// Returns `Ok(true)` if all functions are fresh, `Ok(false)` if any are stale or removed.
2904→// Each argument corresponds to a CLI flag; this is only called from one callsite.
2905→#[allow(clippy::too_many_arguments)]
2906→async fn run_stale(
2907→    source: &str,
2908→    spec_path: &Path,
2909→    format: &str,
2910→    request_timeout: u64,
2911→    exec_timeout: u64,
2912→    build_timeout: u64,
2913→    memory_limit: Option<u64>,
2914→    log_level: LogLevel,
2915→    project_dir: Option<&Path>,
2916→) -> Result<bool, Box<dyn std::error::Error>> {
2917→    let target = parse_target(source)?;
2918→    let file_str = target.file.to_string_lossy();
2919→    let project_root_str = resolve_project_root(project_dir, &target.file);
2920→
2921→    let req_timeout = Duration::from_secs(request_timeout);
2922→    let config = frontend_config(target.language, req_timeout, log_level, exec_timeout, build_timeout, memory_limit, None)?;
2923→    let mut frontend = Frontend::spawn(&config).await.map_err(|e| {
2924→        format!("failed to spawn {} frontend: {e}", target.language.label())
2925→    })?;
2926→
2927→    let analyze_response = frontend
2928→        .send(ProtoCommand::Analyze {
2929→            file: file_str.to_string(),
2930→            function: target.function.clone(),
2931→            project_root: project_root_str,
2932→        })
2933→        .await
2934→        .map_err(|e| format!("analyze failed: {e}"))?;
2935→
2936→    let functions = match &analyze_response.result {
2937→        ResponseResult::Analyze { functions } => functions.clone(),
2938→        ResponseResult::Error { code, message, .. } => {
2939→            shutdown_frontend(frontend).await;
2940→            return Err(format!("analyze error ({code:?}): {message}").into());
2941→        }
2942→        other => {
2943→            shutdown_frontend(frontend).await;
2944→            return Err(format!("unexpected analyze response: {other:?}").into());
2945→        }
2946→    };
2947→
2948→    shutdown_frontend(frontend).await;
2949→
2950→    let existing = shatter_core::spec::read_file_spec_bundle(spec_path)
2951→        .map_err(|e| format!("failed to read spec file {}: {e}", spec_path.display()))?;
2952→
2953→    let plan = shatter_core::spec::compute_incremental_plan(&target.file, &functions, &existing)
2954→        .map_err(|e| format!("failed to compute incremental plan: {e}"))?;
2955→
2956→    let all_fresh = plan.stale.is_empty() && plan.removed.is_empty();
2957→
2958→    if format == "json" {
2959→        let output = serde_json::json!({
2960→            "stale": plan.stale,
2961→            "fresh": plan.fresh,
2962→            "removed": plan.removed,
2963→            "all_fresh": all_fresh,
2964→        });
2965→        println!("{}", serde_json::to_string_pretty(&output)?);
2966→    } else {
2967→        if !plan.stale.is_empty() {
2968→            println!("Stale ({}):", plan.stale.len());
2969→            for name in &plan.stale {
2970→                println!("  {name}");
2971→            }
2972→        }
2973→        if !plan.fresh.is_empty() {
2974→            println!("Fresh ({}):", plan.fresh.len());
2975→            for name in &plan.fresh {
2976→                println!("  {name}");
2977→            }
2978→        }
2979→        if !plan.removed.is_empty() {
2980→            println!("Removed ({}):", plan.removed.len());
2981→            for name in &plan.removed {
2982→                println!("  {name}");
2983→            }
2984→        }
2985→        if all_fresh {
2986→            println!("All functions are fresh.");
