    fn cli_parses_stale_with_json_format() {
        let cli = Cli::parse_from([
            "shatter",
            "stale",
            "--format", "json",
            "src/math.ts",
            "spec.json",
        ]);
        match cli.command {
            CliCommand::Stale { format, .. } => {
                assert_eq!(format, "json");
            }
            _ => panic!("expected Stale command"),
        }
    }
}

